<?php
namespace App\Console\Commands;
use App\Models\User;use Database\Seeders\SecurityGovernanceRoleSeeder;use Illuminate\Console\Command;use Illuminate\Support\Facades\Hash;use Illuminate\Support\Str;use Spatie\Permission\Models\Role;
class CreateLocalSecurityReviewerCommand extends Command {
 protected $signature='security:create-local-reviewer {--email=} {--role=security_reviewer} {--name=Local UAT Security Reviewer} {--confirm-production-risk}';protected $description='Create or update a controlled local UAT security reviewer without revealing credentials';
 public function handle():int{if(!app()->environment(['local','testing'])&&!$this->option('confirm-production-risk')){$this->error('This command is local/testing only unless production risk is explicitly confirmed.');return self::FAILURE;}$email=trim((string)$this->option('email'));$role=(string)$this->option('role');if(!filter_var($email,FILTER_VALIDATE_EMAIL)||!in_array($role,['security_reviewer','compliance_reviewer'],true)){$this->error('A valid email and approved reviewer role are required.');return self::FAILURE;}(new SecurityGovernanceRoleSeeder)->run();$user=User::firstOrNew(['email'=>$email]);if(!$user->exists){$user->name=(string)$this->option('name');$user->password=Hash::make(Str::random(64));$user->email_verified_at=null;$user->save();}$user->syncRoles([Role::findByName($role,'web')]);$this->info("Controlled local UAT reviewer {$user->id} is provisioned with role {$role}. Credentials were not displayed.");return self::SUCCESS;}
}
